from spyne import Application, rpc, ServiceBase, Integer, Unicode, Float
from spyne.protocol.soap import Soap11
from spyne.protocol.soap import SoapFault
from spyne.model.primitive import String
from spyne.model.complex import ComplexModel
from spyne.service import Security
from spyne.protocol.soap import SoapFault
from spyne import Server

class Account(ComplexModel):
    account_number = String
    balance = Float

class FinancialService(ServiceBase):
    accounts = {
        '12345': Account(account_number='12345', balance=1000.0),
        '67890': Account(account_number='67890', balance=2000.0),
    }

    @rpc(Unicode, _returns=Float, _soap_action='getBalance')
    def getBalance(self, account_number):
        account = self.accounts.get(account_number)
        if account:
            return account.balance
        raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

    @rpc(Unicode, Float, _returns=Unicode, _soap_action='transferFunds')
    def transferFunds(self, from_account, amount):
        if from_account not in self.accounts:
            raise SoapFault('AccountNotFound', f'Account {from_account} not found.')
        if self.accounts[from_account].balance < amount:
            raise SoapFault('InsufficientFunds', 'Not enough funds to transfer.')
        
        self.accounts[from_account].balance -= amount
        return f'Transferred {amount} from {from_account}.'

    @rpc(Unicode, _returns=Account, _soap_action='getAccountInfo')
    def getAccountInfo(self, account_number):
        account = self.accounts.get(account_number)
        if account:
            return account
        raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

application = Application([FinancialService],
    tns='spyne.examples.financial',
    in_protocol=Soap11(validator='lxml'),
    out_protocol=Soap11()
)

